function getRanges()
    local archs = {[0x3] = 'x86', [0x28] = 'ARM', [0x3E] = 'x86-64', [0xB7] = 'AArch64'}
    local ranges = {}
    local t = gg.getRangesList('^/data/*.so*$')
    local arch = 'unknown'
    for i, v in ipairs(t) do
        if v.type:sub(2, 2) == '-' then
            local t = gg.getValues({{address = v.start, flags = gg.TYPE_DWORD}, {address = v.start + 0x12, flags = gg.TYPE_WORD}})
            if t[1].value == 0x464C457F then
                arch = archs[t[2].value] or 'unknown'
            end
        end	
        if v.type:sub(2, 2) == 'w' then
            v.arch = arch
            table.insert(ranges, v)
        end
    end
    return ranges
end
function out()
local ti = gg.getTargetInfo()
if ti.packageName ~= v.packageName or ti.versionCode ~= v.versionCode or ti.versionName ~= v.versionName or ti.x64 ~= v.x64 then
local x = {[true] = 'x64', [false] = 'x32'} 
gg.alert('The script is generated for the process\n\n'..v.packageName..' '..v.versionName..' ['..v.versionCode..'] '..x[v.x64]..
'\n\nYou selected the process\n\n'..ti.packageName..' '..ti.versionName..' ['..ti.versionCode..'] '..x[ti.x64]..
'\n\nChains may be loaded incorrectly.')
end

local ranges = getRanges()

local ret = {}
local d = {}
local go = false
local arch = {}
for j, p in ipairs(v) do
    if p.map.new == nil then
        local name = p.map.internalName:gsub('^.*/', '')
        for k, r in ipairs(ranges) do
            local rname = r.internalName:gsub('^.*/', '')
            if name == rname and p.map.state == r.state then
                if arch[name] == nil and p.map.arch ~= r.arch then
                    arch[name] = true
                    gg.alert('The script is generated for the '..name..
                        ' library with '..p.map.arch..' architecture, and you chose a process where the '..name..
                        ' library has an '..r.arch..' architecture.')
                end
                p.map.new = r
                break
            end
        end
    end
    if p.map.new ~= nil then
        for i, u in ipairs(p) do
            u.address = u.address - p.map.start + p.map.new.start
            d[u], go = u, true
        end
    end
end

while go do
    local s = gg.getValues(d)
    d, go = {}, false
    for old, new in pairs(s) do
        if old.offset == nil then
            table.insert(ret, new)
        else
            -- CORREÇÃO CRÍTICA NA LEITURA DA ESTRUTURA DO PONTEIRO EM 32-BIT
            if not ti.x64 then 
                if new.value < 0 then new.value = new.value + 4294967296 end
                new.value = new.value & 0xFFFFFFFF 
            end
            for offset, u in pairs(old.offset) do
                u.address = new.value + offset
                d[u], go = u, true
            end
        end
    end
end

gg.loadResults(ret)

end

out()

local r = gg.getResults(1)

if #r > 0 then
    local base = r[1].address

    local edits = {
        {address = base,      flags = gg.TYPE_DWORD, value = 1000},
        {address = base - 4,  flags = gg.TYPE_DWORD, value = 0},
        {address = base + 4,  flags = gg.TYPE_DWORD, value = 0},
        {address = base + 8,  flags = gg.TYPE_DWORD, value = 1000},
        {address = base + 28, flags = gg.TYPE_DWORD, value = 0},
        {address = base + 32, flags = gg.TYPE_DWORD, value = 1000}
    }

    gg.setValues(edits)
    gg.clearResults()
    gg.toast("✅ Sucesso!")
 end
end

-- ========================================================
-- INTERFACE DE MENU PRINCIPAL (UX CAMUFLADA)
-- ========================================================
local function abrirMenuNinja()
    local opcao = gg.choice({
        "🪙 Moedas + 💵 Notas + 🔷 XP  [OK]",
        "❌ Sair do Painel"
    }, nil, "== 🌐 TOWNSHIP-SCRIPT V1.1 Demo 32-bit ==")

    if opcao == 1 then
       executarScript()
    elseif opcao == 2 or opcao == nil then
        gg.toast("ℹ️ Painel encerrado com segurança.")
        os.exit()
    end
end

-- ========================================================
-- LOOP DE CONTROLO DO MENU
-- ========================================================
while true do
    if gg.isVisible(true) then
        gg.setVisible(false)
        abrirMenuNinja()
    end
    gg.sleep(100)
end
